module top_module(
   input         clock, reset, load,
   input [15:0]  loadValue,
   output [15:0] count,
   output        flag);reg [15:0]    inv_countReg = 16'b0;
   wire          flagWire;

   assign flag = flagWire;
   assign count = inv_countReg;

   always @ (posedge clock) begin 
      if (reset)
         inv_countReg <= 16'b0;
      else if (load)
         inv_countReg <= loadValue;
      else if (inv_countReg == {16{1'b1}})
         inv_countReg <= 16'b0;
      else
         inv_countReg <= inv_countReg + 1;
   end

   assign flagWire = (inv_countReg == {16{1'b1}});

endmodule
